#include <libxml/parser.h>

void parseXMLSafely() {
  xmlParserCtxtPtr ctxt = xmlNewParserCtxt();

  // Compliant: disable external entities
  ctxt->options |= XML_PARSE_NOENT;
  ctxt->options &= ~XML_PARSE_DTDLOAD;
  ctxt->options &= ~XML_PARSE_DTDATTR;
  ctxt->options &= ~XML_PARSE_DTDVALID;

  xmlDocPtr doc = xmlCtxtReadFile(ctxt, "file.xml", NULL, ctxt->options);

  xmlFreeParserCtxt(ctxt);
}

// Disable external entity loader
void disableExternalEntities() {
  // Compliant: set custom entity loader that rejects external entities
  xmlSetExternalEntityLoader(NULL);
}
